import axios from "axios";
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useProgress } from "../context/ProgressContext";

const SECTION_LABELS = {
  vocabulary: "📝 Vocabulary",
  phrases: "💬 Phrases",
  sentences: "✍️ Sentences",
  quiz: "🧩 Quiz",
  story: "📖 Story",
  listening: "🎧 Listening",
  speaking: "🎤 Speaking",
  conversation: "🤝 Conversation",
};

const LEVEL_NAMES = [
  "Beginner",
  "Elementary",
  "Intermediate",
  "Upper-Inter.",
  "Advanced",
];
const LEVEL_EMOJIS = ["🌱", "📖", "🗣️", "📡", "🏆"];

const DashboardPage = () => {
  const { user } = useAuth();
  const { allProgress, fetchAllProgress } = useProgress();
  const [stats, setStats] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchAllProgress();
    axios
      .get("/api/progress/stats/overview")
      .then((r) => setStats(r.data))
      .catch(() => {});
  }, []);

  const completed = allProgress.filter((p) => p.isCompleted);
  const inProgress = allProgress.filter(
    (p) =>
      !p.isCompleted && Object.values(p.completedSections || {}).some(Boolean),
  );

  return (
    <div className="space-y-4 w-full max-w-4xl mx-auto px-2 sm:px-4 md:px-6 bg-[rgb(26_24_41/var(--tw-bg-opacity,1))] rounded-2xl p-6 sm:p-8 transition-colors border border-gray-700">
      <h1 className="text-2xl font-extrabold text-gray-200 mb-1 flex items-center gap-2">
        📊 My Progress
      </h1>
      <p className="text-sm text-slate-400 font-bold mb-6">
        Track your English learning journey
      </p>

      {/* Stats grid */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-6">
        {[
          {
            label: "Total XP",
            value: user?.totalXP || 0,
            icon: "⚡",
            color: "text-yellow-600 bg-yellow-50 border-yellow-200",
          },
          {
            label: "Streak",
            value: `${user?.streak || 0} days`,
            icon: "🔥",
            color: "text-orange-600 bg-orange-50 border-orange-200",
          },
          {
            label: "Completed",
            value: completed.length,
            icon: "✅",
            color: "text-green-600 bg-green-50 border-green-200",
          },
          {
            label: "In Progress",
            value: inProgress.length,
            icon: "▶️",
            color: "text-blue-600 bg-blue-50 border-blue-200",
          },
        ].map((s, i) => (
          <div
            key={i}
            className={`${s.color} border-2 rounded-2xl p-4 text-center`}
          >
            <div className="text-2xl mb-1">{s.icon}</div>
            <div className="text-xl font-extrabold">{s.value}</div>
            <div className="text-xs font-bold opacity-70 mt-0.5">{s.label}</div>
          </div>
        ))}
      </div>

      {/* Current Level */}
      <div className="bg-gradient-to-br from-[#0f3460] to-blue-800 rounded-2xl p-5 mb-6 text-white">
        <p className="text-blue-200 text-xs font-bold mb-1">Current Level</p>
        <div className="flex items-center gap-3">
          <span className="text-4xl">
            {LEVEL_EMOJIS[user?.currentLevel || 0]}
          </span>
          <div>
            <h2 className="text-xl font-extrabold">
              {LEVEL_NAMES[user?.currentLevel || 0]}
            </h2>
            <p className="text-blue-200 text-xs">
              Complete more lessons to level up!
            </p>
          </div>
        </div>
      </div>

      {/* Completed Lessons */}
      {completed.length > 0 && (
        <div className="mb-6">
          <h2 className="text-sm font-extrabold text-gray-300 mb-3 flex items-center gap-2">
            ✅ Completed Lessons ({completed.length})
          </h2>
          <div className="space-y-3">
            {completed.map((p) => (
              <div
                key={p._id}
                className="bg-[#221f35] border-2 border-green-200 rounded-2xl p-4 flex items-center justify-between gap-3"
              >
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className="text-xs font-extrabold bg-green-100 text-green-700 px-2 py-0.5 rounded-full">
                      {LEVEL_NAMES[p.level]} · Day {p.day}
                    </span>
                    <span className="text-xs font-bold text-yellow-600">
                      +{p.xpEarned} XP
                    </span>
                  </div>
                  <div className="flex flex-wrap gap-1 mt-2">
                    {Object.entries(p.completedSections || {}).map(([k, v]) =>
                      v ? (
                        <span
                          key={k}
                          className="text-[10px] font-bold bg-green-50 text-green-600 border border-green-200 px-2 py-0.5 rounded-lg"
                        >
                          ✓ {SECTION_LABELS[k]}
                        </span>
                      ) : null,
                    )}
                  </div>
                </div>
                <button
                  onClick={() => navigate(`/lesson/${p.level}/${p.day}`)}
                  className="text-xs text-green-500 font-extrabold hover:underline flex-shrink-0"
                >
                  Review →
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* In Progress */}
      {inProgress.length > 0 && (
        <div className="mb-6">
          <h2 className="text-sm font-extrabold text-gray-200 mb-3 flex items-center gap-2">
            ▶️ In Progress ({inProgress.length})
          </h2>
          <div className="space-y-3">
            {inProgress.map((p) => {
              const done = Object.values(p.completedSections || {}).filter(
                Boolean,
              ).length;
              const pct = Math.round((done / 8) * 100);
              return (
                <div
                  key={p._id}
                  className="bg-[#221f35] border-2 border-blue-200 rounded-2xl p-4"
                >
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-xs font-extrabold bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">
                      {LEVEL_NAMES[p.level]} · Day {p.day}
                    </span>
                    <button
                      onClick={() => navigate(`/lesson/${p.level}/${p.day}`)}
                      className="text-xs text-green-500 font-extrabold hover:underline"
                    >
                      Continue →
                    </button>
                  </div>
                  <div className="h-2 bg-slate-100 rounded-full overflow-hidden mb-2">
                    <div
                      className="h-full bg-gradient-to-r from-blue-900 to-pink-500 rounded-full transition-all duration-500"
                      style={{ width: `${pct}%` }}
                    />
                  </div>
                  <p className="text-xs text-gray-400 font-bold">
                    {done}/8 sections · {pct}% complete
                  </p>
                  <div className="flex flex-wrap gap-1 mt-2">
                    {Object.entries(p.completedSections || {}).map(([k, v]) => (
                      <span
                        key={k}
                        className={`text-[10px] font-bold px-2 py-0.5 rounded-lg border
                        ${v ? "bg-green-50 text-green-600 border-green-200" : "bg-slate-50 text-slate-400 border-slate-200"}`}
                      >
                        {v ? "✓ " : ""}
                        {SECTION_LABELS[k]}
                      </span>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {allProgress.length === 0 && (
        <div className="text-center py-16">
          <div className="text-6xl mb-4">📚</div>
          <h3 className="font-playfair text-xl text-gray-200 mb-2">
            No lessons started yet
          </h3>
          <p className="text-sm text-gray-400 mb-5">
            Start your first lesson to see your progress here!
          </p>
          <button
            onClick={() => navigate("/")}
            className="bg-blue-900 text-white font-bold px-6 py-3 rounded-xl text-sm hover:bg-blue-800 transition-all hover:-translate-y-0.5"
          >
            Go to Lessons →
          </button>
        </div>
      )}
    </div>
  );
}

export default DashboardPage;
